function solve(nums) {
    // This problem asks for the maximum number of fixed points we can achieve
    // after deleting any number of elements.
    // When an element at original index i is kept, its new index j depends
    // on how many elements before it (at original indices k < i) were deleted.
    // New index j = (number of kept elements before i).
    // A fixed point occurs if nums[i] == j.
    // So, we are looking for a subsequence of indices $i_1, i_2, ..., i_k$ such that
    // if $j = 1, 2, ..., k$ is the new index, then $nums[i_j] = j$.

    // Let's rephrase: We want to select a set of indices $i_1 < i_2 < ... < i_k$
    // such that $nums[i_j] = j$.

    // This is equivalent to finding the longest subsequence $i_1, i_2, ..., i_k$
    // such that $nums[i_j] = j$.

    // This is a dynamic programming or greedy problem. Since the target value $j$
    // is strictly increasing (1, 2, 3, ...), a greedy approach works.

    let maxFixedPoints = 0;
    let requiredValue = 1; // We are looking for the first fixed point at new index 1

    for (let i = 0; i < nums.length; i++) {
        // If the current element nums[i] is equal to the value we are currently
        // looking for (requiredValue), we choose to keep this element and count it
        // as a fixed point at the new index 'requiredValue'.
        if (nums[i] === requiredValue) {
            maxFixedPoints++;
            requiredValue++; // Now we look for the next fixed point at new index 'requiredValue'
        }
    }

    return maxFixedPoints;
